#Desafio: análise basica de sequencia de DNA

#Dada a seguinte sequencia = ""

#Calcule:

#1️ Tamanho da sequência
#2️ Número de vezes que aparece a base C
#3️ Número de vezes que aparece a base G
#4️ Porcentagem de C G

sequence = ""
length = len(sequence)
print("Sequence length =", length)
count_C = sequence.count("C")
print("Number of C =", count_C)
count_G = sequence.count("G")
print("Number of G =", count_G)
percentage_CG = (count_C + count_G) / length * 100
print("GC% =", percentage_CG, "%")